// ==================== 全局变量 ====================
let map = null;
let isNightMode = false;
let isAutoRotating = false;
let currentInfoWindow = null;

// ==================== 初始化 ====================
function init() {
    // 检查高德地图API是否加载
    if (typeof AMap === 'undefined') {
        console.error('高德地图API未加载');
        showApiKeyNotice();
        return;
    }

    // 检查API Key
    if (CONFIG.AMAP_KEY === 'YOUR_AMAP_KEY') {
        console.warn('请配置高德地图API Key');
        showApiKeyNotice();
    }

    // 初始化地图
    initMap();
    
    // 绑定事件
    bindEvents();
    
    // 隐藏加载画面
    setTimeout(() => {
        document.getElementById('loading').classList.add('hidden');
    }, 1500);
}

// ==================== 地图初始化 ====================
function initMap() {
    try {
        map = new AMap.Map('amap-container', {
            viewMode: '3D',
            pitch: 60,
            zoom: CONFIG.DEFAULT_ZOOM,
            center: CONFIG.CENTER,
            mapStyle: 'amap://styles/darkblue',
            showBuildingBlock: true,
            buildingAnimation: true,
            skyColor: '#1a1a2e'
        });

        // 添加3D建筑图层
        if (CONFIG.ENABLE_3D_BUILDINGS) {
            addBuildingsLayer();
        }

        // 添加标记点
        addMarkers();

        // 添加控件
        addControls();

        console.log('高德地图初始化成功');

    } catch (error) {
        console.error('高德地图初始化失败:', error);
        document.getElementById('loading').innerHTML = '<p>地图加载失败，请检查API Key</p>';
    }
}

// ==================== 添加3D建筑图层 ====================
function addBuildingsLayer() {
    try {
        const buildings = new AMap.Buildings({
            zooms: [14, 20],
            zIndex: 10,
            heightFactor: 1.5,
            visible: true
        });
        
        map.add(buildings);
    } catch (error) {
        console.warn('3D建筑图层加载失败:', error);
    }
}

// ==================== 添加标记点 ====================
function addMarkers() {
    // 添加街道标记
    LOCATIONS_DATA.streets.forEach(street => {
        addLocationMarker(street, 'street');
    });

    // 添加地标标记
    LOCATIONS_DATA.landmarks.forEach(landmark => {
        addLocationMarker(landmark, 'landmark');
    });
}

// ==================== 添加单个标记 ====================
function addLocationMarker(location, type) {
    const marker = new AMap.Marker({
        position: location.position,
        title: location.name,
        animation: 'AMAP_ANIMATION_DROP',
        label: {
            content: `<div style="background: rgba(0,0,0,0.7); color: white; padding: 5px 10px; border-radius: 4px; font-size: 12px; white-space: nowrap;">${location.name}</div>`,
            offset: new AMap.Pixel(0, -35)
        }
    });

    // 点击事件
    marker.on('click', () => {
        showLocationInfo(location, type);
    });

    map.add(marker);
}

// ==================== 添加地图控件 ====================
function addControls() {
    // 添加缩放控件
    map.addControl(new AMap.Scale());
    
    // 添加工具条
    map.addControl(new AMap.ToolBar({
        position: 'RB'
    }));
}

// ==================== 显示位置信息 ====================
function showLocationInfo(location, type) {
    // 关闭之前的信息窗
    if (currentInfoWindow) {
        currentInfoWindow.close();
    }

    // 创建信息窗内容
    const content = `
        <div style="padding: 10px; max-width: 300px;">
            <h3 style="margin-bottom: 10px; color: #1a1a2e; font-size: 18px;">${location.name}</h3>
            <span style="display: inline-block; padding: 4px 10px; background: linear-gradient(135deg, #00d4ff, #0099cc); color: white; border-radius: 20px; font-size: 12px; margin-bottom: 10px;">${type === 'street' ? '历史街道' : '地标建筑'}</span>
            <p style="color: #666; font-size: 14px; line-height: 1.5; margin-bottom: 10px;">${location.description}</p>
            <h4 style="color: #1a1a2e; font-size: 14px; margin: 10px 0 5px;">📜 历史沿革</h4>
            <p style="color: #666; font-size: 13px; line-height: 1.5;">${location.history}</p>
            <h4 style="color: #1a1a2e; font-size: 14px; margin: 10px 0 5px;">✨ 特色亮点</h4>
            <p style="color: #666; font-size: 13px; line-height: 1.5;">${location.features}</p>
        </div>
    `;

    // 创建信息窗
    currentInfoWindow = new AMap.InfoWindow({
        content: content,
        position: location.position,
        offset: new AMap.Pixel(0, -30),
        autoMove: true
    });

    currentInfoWindow.open(map);

    // 同时显示在右侧面板
    showInfoPanel(location, type);

    // 飞转到该位置
    map.setZoomAndCenter(17, location.position);
}

// ==================== 显示信息面板 ====================
function showInfoPanel(location, type) {
    const panel = document.getElementById('info-panel');
    const title = document.getElementById('info-title');
    const content = document.getElementById('info-content');

    title.textContent = location.name;
    
    const icon = type === 'street' ? '🛣️' : '🏛️';
    const typeText = type === 'street' ? '历史街道' : '地标建筑';
    
    let html = `<div class="icon" style="font-size: 48px; text-align: center; margin-bottom: 15px;">${icon}</div>`;
    html += `<span class="tag" style="display: inline-block; padding: 4px 10px; background: linear-gradient(135deg, #00d4ff, #0099cc); color: white; border-radius: 20px; font-size: 12px; margin-bottom: 10px;">${typeText}</span>`;
    html += `<p style="margin-bottom: 10px; color: #555;">${location.description}</p>`;
    html += `<h3 style="color: #1a1a2e; font-size: 16px; margin-top: 15px; margin-bottom: 8px; padding-bottom: 5px; border-bottom: 2px solid #00d4ff;">📜 历史沿革</h3>`;
    html += `<p style="margin-bottom: 10px; color: #555;">${location.history}</p>`;
    html += `<h3 style="color: #1a1a2e; font-size: 16px; margin-top: 15px; margin-bottom: 8px; padding-bottom: 5px; border-bottom: 2px solid #00d4ff;">✨ 特色亮点</h3>`;
    html += `<p style="margin-bottom: 10px; color: #555;">${location.features}</p>`;
    
    content.innerHTML = html;
    panel.classList.remove('hidden');
}

// ==================== 绑定事件 ====================
function bindEvents() {
    // 窗口大小变化
    window.addEventListener('resize', () => {
        if (map) {
            map.resize();
        }
    });

    // 控制按钮
    document.getElementById('reset-view').addEventListener('click', resetView);
    document.getElementById('toggle-rotate').addEventListener('click', toggleRotation);
    document.getElementById('zoom-in').addEventListener('click', () => zoom(1));
    document.getElementById('zoom-out').addEventListener('click', () => zoom(-1));
    document.getElementById('close-info').addEventListener('click', closeInfoPanel);
    document.getElementById('night-mode').addEventListener('click', toggleNightMode);

    // 侧边栏导航
    bindSidebarNavigation();
}

// ==================== 绑定侧边栏导航 ====================
function bindSidebarNavigation() {
    const streetList = document.getElementById('street-list');
    const landmarkList = document.getElementById('landmark-list');

    // 街道点击
    streetList.querySelectorAll('li').forEach(li => {
        li.addEventListener('click', () => {
            const lng = parseFloat(li.dataset.lng);
            const lat = parseFloat(li.dataset.lat);
            const name = li.textContent;
            
            const location = LOCATIONS_DATA.streets.find(s => s.name === name);
            if (location) {
                showLocationInfo(location, 'street');
            } else {
                map.setZoomAndCenter(17, [lng, lat]);
            }
        });
    });

    // 地标点击
    landmarkList.querySelectorAll('li').forEach(li => {
        li.addEventListener('click', () => {
            const lng = parseFloat(li.dataset.lng);
            const lat = parseFloat(li.dataset.lat);
            const name = li.textContent;
            
            const location = LOCATIONS_DATA.landmarks.find(l => l.name === name);
            if (location) {
                showLocationInfo(location, 'landmark');
            } else {
                map.setZoomAndCenter(17, [lng, lat]);
            }
        });
    });
}

// ==================== 控制功能 ====================
function resetView() {
    if (!map) return;
    map.setZoomAndCenter(CONFIG.DEFAULT_ZOOM, CONFIG.CENTER);
    map.setPitch(60);
    
    if (currentInfoWindow) {
        currentInfoWindow.close();
    }
    closeInfoPanel();
}

function toggleRotation() {
    if (!map) return;
    
    isAutoRotating = !isAutoRotating;
    const btn = document.getElementById('toggle-rotate');
    btn.textContent = isAutoRotating ? '停止旋转' : '自动旋转';
    btn.style.background = isAutoRotating ? 'rgba(0, 212, 255, 0.3)' : '';
    
    if (isAutoRotating) {
        startRotation();
    } else {
        stopRotation();
    }
}

let rotationInterval = null;
function startRotation() {
    if (rotationInterval) return;
    
    let rotation = 0;
    rotationInterval = setInterval(() => {
        rotation += 0.5;
        map.setRotation(rotation);
    }, 50);
}

function stopRotation() {
    if (rotationInterval) {
        clearInterval(rotationInterval);
        rotationInterval = null;
    }
}

function zoom(direction) {
    if (!map) return;
    const currentZoom = map.getZoom();
    map.setZoom(currentZoom + direction);
}

function toggleNightMode() {
    if (!map) return;
    
    isNightMode = !isNightMode;
    const btn = document.getElementById('night-mode');
    
    if (isNightMode) {
        btn.textContent = '☀️ 日间模式';
        btn.classList.add('active');
        map.setMapStyle('amap://styles/darkblue');
    } else {
        btn.textContent = '🌙 夜景模式';
        btn.classList.remove('active');
        map.setMapStyle('amap://styles/normal');
    }
}

function closeInfoPanel() {
    document.getElementById('info-panel').classList.add('hidden');
}

function showApiKeyNotice() {
    document.getElementById('api-key-notice').style.display = 'block';
    setTimeout(() => {
        document.getElementById('api-key-notice').style.display = 'none';
    }, 5000);
}

// ==================== 启动 ====================
// 等待高德地图API加载完成
if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', init);
} else {
    init();
}
